export enum UserRole {
  ADMIN = 'ADMIN',
  CASHIER = 'CASHIER'
}

export interface Product {
  id: string;
  barcode: string;
  name: string;
  category: string;
  price: number;
  cost: number;
  stock: number;
  minStock: number;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface Transaction {
  id: string;
  date: string;
  items: CartItem[];
  total: number;
  tax: number;
  discount: number;
  paymentMethod: 'CASH' | 'CARD' | 'QRIS';
  cashierId: string;
  cashierName: string;
}

export interface Employee {
  id: string;
  name: string;
  role: UserRole;
  status: 'ACTIVE' | 'INACTIVE';
  lastLogin: string;
}

export type View = 'DASHBOARD' | 'POS' | 'INVENTORY' | 'HISTORY' | 'EMPLOYEES' | 'REPORTS';

import { Product, Employee, UserRole } from './types';

