import { GoogleGenAI } from "@google/genai";
import { Transaction, Product } from "./types";

export const getSalesAnalysis = async (transactions: Transaction[], inventory: Product[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const summary = {
    totalSales: transactions.reduce((acc, t) => acc + t.total, 0),
    count: transactions.length,
    lowStock: inventory.filter(i => i.stock <= i.minStock).map(i => i.name),
  };

  const prompt = `Analyze the following retail data and provide 3 key business insights and 1 action recommendation in Indonesian:
  Data:
  - Total Transactions: ${summary.count}
  - Total Revenue: ${summary.totalSales}
  - Low Stock Items: ${summary.lowStock.join(', ')}
  - Latest 5 Transactions Data: ${JSON.stringify(transactions.slice(-5))}

  Format: Bullet points, professional tone. Focus on profit, stock levels, and sales trends.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("AI Analysis failed:", error);
    return "Analysis currently unavailable. Please check your connection.";
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  LayoutDashboard, 
  ShoppingCart, 
  Package, 
  History, 
  Users, 
  BarChart3, 
  Menu, 
  LogOut,
  Scan,
  Bell,
  Search
} from 'lucide-react';
import { View, Product, CartItem, Transaction, Employee, UserRole } from './types';
import { INITIAL_PRODUCTS, INITIAL_EMPLOYEES } from './constants';
import DashboardView from './components/DashboardView';
import POSView from './components/POSView';
import InventoryView from './components/InventoryView';
import HistoryView from './components/HistoryView';
import EmployeesView from './components/EmployeesView';
import ReportsView from './components/ReportsView';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>('DASHBOARD');
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('nexus_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('nexus_transactions');
    return saved ? JSON.parse(saved) : [];
  });
  const [employees] = useState<Employee[]>(INITIAL_EMPLOYEES);
  const [currentUser] = useState<Employee>(INITIAL_EMPLOYEES[0]); // Mock login
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Sync with LocalStorage
  useEffect(() => {
    localStorage.setItem('nexus_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('nexus_transactions', JSON.stringify(transactions));
  }, [transactions]);

  const handleCompleteTransaction = useCallback((transaction: Transaction) => {
    // Update Stock
    setProducts(prev => prev.map(p => {
      const cartItem = transaction.items.find(item => item.id === p.id);
      if (cartItem) {
        return { ...p, stock: p.stock - cartItem.quantity };
      }
      return p;
    }));
    // Record Transaction
    setTransactions(prev => [...prev, transaction]);
  }, []);

  const menuItems = [
    { id: 'DASHBOARD', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'POS', label: 'Checkout', icon: ShoppingCart },
    { id: 'INVENTORY', label: 'Stok Barang', icon: Package },
    { id: 'HISTORY', label: 'Riwayat', icon: History },
    { id: 'EMPLOYEES', label: 'Karyawan', icon: Users },
    { id: 'REPORTS', label: 'Laporan', icon: BarChart3 },
  ];

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50">
      {/* Sidebar */}
      <aside className={`bg-slate-900 text-white transition-all duration-300 ${isSidebarOpen ? 'w-64' : 'w-20'} flex flex-col shrink-0`}>
        <div className="p-6 flex items-center gap-3">
          <div className="bg-indigo-500 p-2 rounded-lg">
            <Scan size={24} />
          </div>
          {isSidebarOpen && <span className="font-bold text-xl tracking-tight">NEXUS<span className="text-indigo-400">POS</span></span>}
        </div>

        <nav className="flex-1 mt-6 px-3 space-y-1">
          {menuItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveView(item.id as View)}
              className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-200 ${
                activeView === item.id 
                ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' 
                : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <item.icon size={20} />
              {isSidebarOpen && <span className="font-medium text-sm">{item.label}</span>}
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className={`flex items-center gap-3 ${isSidebarOpen ? '' : 'justify-center'}`}>
            <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center font-bold text-xs">
              {currentUser.name.charAt(0)}
            </div>
            {isSidebarOpen && (
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium truncate">{currentUser.name}</p>
                <p className="text-xs text-slate-500 uppercase tracking-wider">{currentUser.role}</p>
              </div>
            )}
            {isSidebarOpen && <LogOut size={16} className="text-slate-500 cursor-pointer hover:text-white" />}
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0">
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500">
            <Menu size={20} />
          </button>

          <div className="flex items-center gap-6">
            <div className="relative hidden sm:block">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Cari transaksi atau produk..." 
                className="pl-10 pr-4 py-2 bg-slate-100 border-none rounded-full text-sm w-64 focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
              />
            </div>
            <div className="relative cursor-pointer">
              <Bell size={20} className="text-slate-500" />
              <span className="absolute top-0 right-0 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
            </div>
            <div className="text-right">
              <p className="text-xs text-slate-400 font-medium">{new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long' })}</p>
              <p className="text-sm font-bold text-slate-700">Audit Status: <span className="text-green-500">Normal</span></p>
            </div>
          </div>
        </header>

        {/* View Content */}
        <div className="flex-1 overflow-y-auto p-6 bg-slate-50">
          {activeView === 'DASHBOARD' && <DashboardView transactions={transactions} products={products} />}
          {activeView === 'POS' && <POSView products={products} onComplete={handleCompleteTransaction} currentUser={currentUser} />}
          {activeView === 'INVENTORY' && <InventoryView products={products} setProducts={setProducts} />}
          {activeView === 'HISTORY' && <HistoryView transactions={transactions} />}
          {activeView === 'EMPLOYEES' && <EmployeesView employees={employees} />}
          {activeView === 'REPORTS' && <ReportsView transactions={transactions} products={products} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { TrendingUp, ShoppingBag, PackageX, DollarSign, BrainCircuit } from 'lucide-react';
import { Transaction, Product } from '../types';
import { getSalesAnalysis } from '../geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

interface Props {
  transactions: Transaction[];
  products: Product[];
}

const DashboardView: React.FC<Props> = ({ transactions, products }) => {
  const [aiInsight, setAiInsight] = useState<string>('Menganalisis data...');
  const [loadingAi, setLoadingAi] = useState(true);

  const totalRevenue = transactions.reduce((acc, t) => acc + t.total, 0);
  const totalProfit = transactions.reduce((acc, t) => {
    const cost = t.items.reduce((sum, item) => sum + (item.cost * item.quantity), 0);
    return acc + (t.total - cost);
  }, 0);
  const lowStockCount = products.filter(p => p.stock <= p.minStock).length;

  useEffect(() => {
    const fetchAi = async () => {
      setLoadingAi(true);
      const insight = await getSalesAnalysis(transactions, products);
      setAiInsight(insight || 'Belum ada wawasan yang tersedia saat ini.');
      setLoadingAi(false);
    };
    fetchAi();
  }, [transactions, products]);

  // Chart Data preparation
  const chartData = transactions.slice(-10).map(t => ({
    name: new Date(t.date).toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' }),
    total: t.total,
  }));

  const stats = [
    { label: 'Total Pendapatan', value: `Rp ${totalRevenue.toLocaleString()}`, icon: DollarSign, color: 'text-emerald-600', bg: 'bg-emerald-50' },
    { label: 'Total Laba', value: `Rp ${totalProfit.toLocaleString()}`, icon: TrendingUp, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: 'Transaksi Hari Ini', value: transactions.length, icon: ShoppingBag, color: 'text-orange-600', bg: 'bg-orange-50' },
    { label: 'Stok Menipis', value: lowStockCount, icon: PackageX, color: 'text-red-600', bg: 'bg-red-50' },
  ];

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <h1 className="text-2xl font-bold text-slate-800">Dashboard</h1>
        <div className="flex gap-2">
          <span className="px-3 py-1 bg-white border border-slate-200 rounded-lg text-xs font-medium text-slate-500 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-green-500"></span> Live Update
          </span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-all">
            <div className="flex items-center gap-4">
              <div className={`${stat.bg} p-3 rounded-xl`}>
                <stat.icon className={stat.color} size={24} />
              </div>
              <div>
                <p className="text-sm text-slate-500 font-medium">{stat.label}</p>
                <p className="text-xl font-bold text-slate-800">{stat.value}</p>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Chart */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Alur Penjualan Terkini</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData}>
                <defs>
                  <linearGradient id="colorTotal" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
                <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#fff', borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                />
                <Area type="monotone" dataKey="total" stroke="#4f46e5" strokeWidth={3} fillOpacity={1} fill="url(#colorTotal)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* AI Insight Card */}
        <div className="bg-indigo-900 text-white p-6 rounded-2xl shadow-xl flex flex-col relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 opacity-10">
            <BrainCircuit size={120} />
          </div>
          <div className="relative z-10 flex flex-col h-full">
            <div className="flex items-center gap-3 mb-4">
              <BrainCircuit className="text-indigo-300" />
              <h3 className="text-lg font-bold">AI Business Insights</h3>
            </div>
            <div className="flex-1 text-sm text-indigo-100 leading-relaxed overflow-y-auto">
              {loadingAi ? (
                <div className="flex flex-col items-center justify-center h-full gap-3">
                  <div className="w-8 h-8 border-4 border-indigo-400 border-t-transparent rounded-full animate-spin"></div>
                  <p>Menganalisis perilaku belanja...</p>
                </div>
              ) : (
                <div className="prose prose-invert prose-sm">
                  {aiInsight.split('\n').map((line, idx) => (
                    <p key={idx} className="mb-2">{line}</p>
                  ))}
                </div>
              )}
            </div>
            <button className="mt-6 w-full py-2 bg-white/10 hover:bg-white/20 rounded-xl transition-all font-medium text-xs backdrop-blur-sm">
              Tampilkan Laporan Detail
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DashboardView;

import React, { useState, useEffect, useRef } from 'react';
import { Search, Plus, Minus, Trash2, CreditCard, Banknote, QrCode, ScanLine, Camera } from 'lucide-react';
import { Product, CartItem, Transaction, Employee } from '../types';

interface Props {
  products: Product[];
  onComplete: (transaction: Transaction) => void;
  currentUser: Employee;
}

const POSView: React.FC<Props> = ({ products, onComplete, currentUser }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [search, setSearch] = useState('');
  const [showScanner, setShowScanner] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'CARD' | 'QRIS'>('CASH');
  const videoRef = useRef<HTMLVideoElement>(null);

  const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const tax = subtotal * 0.11; // 11% tax
  const total = subtotal + tax;

  const filteredProducts = products.filter(p => 
    p.name.toLowerCase().includes(search.toLowerCase()) || 
    p.barcode.includes(search)
  );

  const addToCart = (product: Product) => {
    if (product.stock <= 0) return alert('Stok habis!');

    setCart(prev => {
      const existing = prev.find(p => p.id === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) {
          alert('Stok maksimum tercapai!');
          return prev;
        }
        return prev.map(p => p.id === product.id ? { ...p, quantity: p.quantity + 1 } : p);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(p => {
      if (p.id === id) {
        const newQty = Math.max(0, p.quantity + delta);
        if (newQty > p.stock) return p;
        return { ...p, quantity: newQty };
      }
      return p;
    }).filter(p => p.quantity > 0));
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const newTransaction: Transaction = {
      id: `TXN-${Date.now()}`,
      date: new Date().toISOString(),
      items: [...cart],
      total,
      tax,
      discount: 0,
      paymentMethod,
      cashierId: currentUser.id,
      cashierName: currentUser.name
    };

    onComplete(newTransaction);
    setCart([]);
    alert('Transaksi Berhasil!');
  };

  // Mock Barcode Scanner Logic
  const simulateScan = () => {
    const randomProduct = products[Math.floor(Math.random() * products.length)];
    addToCart(randomProduct);
    setShowScanner(false);
  };

  useEffect(() => {
    if (showScanner && videoRef.current) {
      navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } })
        .then(stream => {
          if (videoRef.current) videoRef.current.srcObject = stream;
        })
        .catch(err => console.error("Camera access denied", err));
    }
  }, [showScanner]);

  return (
    <div className="h-full flex flex-col lg:flex-row gap-6">
      {/* Product Selection */}
      <div className="flex-1 flex flex-col min-w-0">
        <div className="bg-white p-4 rounded-2xl border border-slate-200 mb-4 flex gap-4">
          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Cari barcode atau nama produk..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-slate-100 rounded-xl border-none outline-none focus:ring-2 focus:ring-indigo-500"
            />
          </div>
          <button 
            onClick={() => setShowScanner(true)}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors"
          >
            <ScanLine size={18} />
            <span className="hidden sm:inline">Scan Barcode</span>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4 pb-4">
          {filteredProducts.map(product => (
            <button
              key={product.id}
              onClick={() => addToCart(product)}
              className="bg-white p-4 rounded-2xl border border-slate-200 hover:border-indigo-500 hover:shadow-lg transition-all text-left flex flex-col group"
            >
              <div className="w-full aspect-square bg-slate-50 rounded-xl mb-3 flex items-center justify-center group-hover:bg-indigo-50 transition-colors">
                <Package className="text-slate-300 group-hover:text-indigo-400" size={48} />
              </div>
              <h4 className="font-bold text-slate-800 text-sm truncate">{product.name}</h4>
              <p className="text-xs text-slate-400 mb-2">{product.category}</p>
              <div className="mt-auto flex justify-between items-center">
                <span className="font-bold text-indigo-600">Rp {product.price.toLocaleString()}</span>
                <span className={`text-[10px] px-2 py-0.5 rounded-full ${product.stock > 10 ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
                  Stok: {product.stock}
                </span>
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Cart & Checkout */}
      <div className="w-full lg:w-96 bg-white rounded-2xl border border-slate-200 shadow-xl flex flex-col sticky top-0 h-full">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between">
          <h3 className="font-bold text-lg text-slate-800">Keranjang Belanja</h3>
          <span className="bg-indigo-100 text-indigo-600 px-3 py-1 rounded-full text-xs font-bold">{cart.length} Item</span>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {cart.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 gap-4 opacity-60">
              <ShoppingCart size={64} />
              <p className="text-sm font-medium">Keranjang masih kosong</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.id} className="flex gap-3">
                <div className="w-12 h-12 bg-slate-100 rounded-lg flex items-center justify-center shrink-0">
                  <Package size={20} className="text-slate-400" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-bold text-slate-800 truncate">{item.name}</p>
                  <p className="text-xs text-indigo-600 font-medium">Rp {item.price.toLocaleString()}</p>
                </div>
                <div className="flex items-center gap-2">
                  <button onClick={() => updateQuantity(item.id, -1)} className="p-1 text-slate-400 hover:text-indigo-600">
                    <Minus size={14} />
                  </button>
                  <span className="w-6 text-center text-sm font-bold">{item.quantity}</span>
                  <button onClick={() => updateQuantity(item.id, 1)} className="p-1 text-slate-400 hover:text-indigo-600">
                    <Plus size={14} />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-6 bg-slate-50 border-t border-slate-200 space-y-4">
          <div className="space-y-2">
            <div className="flex justify-between text-sm text-slate-500">
              <span>Subtotal</span>
              <span>Rp {subtotal.toLocaleString()}</span>
            </div>
            <div className="flex justify-between text-sm text-slate-500">
              <span>Pajak (11%)</span>
              <span>Rp {tax.toLocaleString()}</span>
            </div>
            <div className="flex justify-between text-lg font-bold text-slate-800 pt-2 border-t border-slate-200">
              <span>Total</span>
