      id: `TXN-${Date.now()}`,
      date: new Date().toISOString(),
      items: [...cart],
      total,
      tax,
      discount: 0,
      paymentMethod,
      cashierId: currentUser.id,
      cashierName: currentUser.name
    };

    onComplete(newTransaction);
    setCart([]);
    alert('Pembayaran Berhasil! Inventaris telah diperbarui secara otomatis.');
  };

  const simulateScan = () => {
    const randomProduct = products[Math.floor(Math.random() * products.length)];
    addToCart(randomProduct);
    setShowScanner(false);
  };

  useEffect(() => {
    let stream: MediaStream | null = null;
    if (showScanner && videoRef.current) {
      navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } })
        .then(s => {
          stream = s;
          if (videoRef.current) videoRef.current.srcObject = s;
        })
        .catch(err => console.error("Akses kamera ditolak", err));
    }
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [showScanner]);

  return (
    <div className="h-full flex flex-col lg:flex-row gap-6 animate-in fade-in duration-300">
      <div className="flex-1 flex flex-col min-w-0">
        <div className="bg-white p-4 rounded-2xl border border-slate-200 mb-4 flex gap-4 shadow-sm">
          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Cari barcode atau nama produk..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 bg-slate-50 rounded-xl border-none outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
            />
