import React, { useState, useEffect, useRef } from 'react';
import { 
  Search, 
  Plus, 
  Minus, 
  Trash2, 
  CreditCard, 
  Banknote, 
  QrCode, 
  ScanLine, 
  Camera,
  ShoppingCart,
  Package,
  X,
  CheckCircle2,
  Printer,
  AlertCircle
} from 'lucide-react';
import { Product, CartItem, Transaction, Employee } from '../types';

interface Props {
  products: Product[];
  onComplete: (transaction: Transaction) => void;
  currentUser: Employee;
}

const POSView: React.FC<Props> = ({ products, onComplete, currentUser }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [search, setSearch] = useState('');
  const [showScanner, setShowScanner] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'CARD' | 'QRIS'>('CASH');
  const [cashReceived, setCashReceived] = useState<number>(0);
  const [showReceipt, setShowReceipt] = useState<Transaction | null>(null);
  const [manualBarcode, setManualBarcode] = useState('');
  const [isDetectorSupported, setIsDetectorSupported] = useState(true);
  const [lastScannedCode, setLastScannedCode] = useState<string | null>(null);
  const [scanFeedback, setScanFeedback] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const barcodeInputRef = useRef<HTMLInputElement>(null);
  const scanTimerRef = useRef<number | null>(null);

  const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const tax = subtotal * 0.11;
  const total = subtotal + tax;
  const changeDue = Math.max(0, cashReceived - total);

  const filteredProducts = products.filter(p => 
    p.name.toLowerCase().includes(search.toLowerCase()) || 
    p.barcode.includes(search)
  );

  // Play Beep Sound
  const playBeep = () => {
    const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const oscillator = audioCtx.createOscillator();
    const gainNode = audioCtx.createGain();

    oscillator.type = 'sine';
    oscillator.frequency.setValueAtTime(880, audioCtx.currentTime); // A5 note
    gainNode.gain.setValueAtTime(0.1, audioCtx.currentTime);
    gainNode.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.1);

    oscillator.connect(gainNode);
    gainNode.connect(audioCtx.destination);

    oscillator.start();
    oscillator.stop(audioCtx.currentTime + 0.1);
  };

  const addToCart = (product: Product) => {
    if (product.stock <= 0) {
      alert(`Stok untuk ${product.name} telah habis!`);
      return;
    }

    setCart(prev => {
      const existing = prev.find(p => p.id === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) {
          alert('Stok maksimum di gudang telah tercapai!');
          return prev;
        }
        return prev.map(p => p.id === product.id ? { ...p, quantity: p.quantity + 1 } : p);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const handleBarcodeDetect = (code: string) => {
    if (code === lastScannedCode) return false; // Prevent double scans

    const product = products.find(p => p.barcode === code);
    if (product) {
      addToCart(product);
      setLastScannedCode(code);
      setScanFeedback(true);
      playBeep();

      // Reset feedback and cool-down after 1.5 seconds
      setTimeout(() => {
        setScanFeedback(false);
        setLastScannedCode(null);
      }, 1500);

      return true;
    }
    return false;
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(p => {
      if (p.id === id) {
        const newQty = Math.max(0, p.quantity + delta);
        const productRef = products.find(prod => prod.id === id);
        if (productRef && newQty > productRef.stock) {
          alert('Melebihi stok yang tersedia!');
          return p;
        }
        return { ...p, quantity: newQty };
      }
      return p;
    }).filter(p => p.quantity > 0));
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;
    if (paymentMethod === 'CASH' && cashReceived < total) {
      alert('Uang tunai yang diterima kurang dari total belanja!');
      return;
    }

    const newTransaction: Transaction = {
      id: `TXN-${Date.now()}`,
      date: new Date().toISOString(),
      items: [...cart],
      total,
      tax,
      discount: 0,
      paymentMethod,
      amountPaid: paymentMethod === 'CASH' ? cashReceived : total,
      changeDue: paymentMethod === 'CASH' ? changeDue : 0,
      cashierId: currentUser.id,
      cashierName: currentUser.name
    };

    onComplete(newTransaction);
    setShowReceipt(newTransaction);
    setCart([]);
    setCashReceived(0);
  };

  // Real-time Barcode Detection Loop
  useEffect(() => {
    let stream: MediaStream | null = null;
    let detector: any = null;

    const startDetection = async () => {
      if (!('BarcodeDetector' in window)) {
        setIsDetectorSupported(false);
        return;
      }

      try {
        detector = new (window as any).BarcodeDetector({ formats: ['ean_13', 'code_128', 'qr_code', 'upc_a'] });

        const detectFrame = async () => {
          if (videoRef.current && videoRef.current.readyState === videoRef.current.HAVE_ENOUGH_DATA) {
            try {
              const barcodes = await detector.detect(videoRef.current);
              if (barcodes.length > 0) {
                const code = barcodes[0].rawValue;
                handleBarcodeDetect(code);
              }
            } catch (err) {
              console.error("Detection error:", err);
            }
          }
          if (showScanner) {
            scanTimerRef.current = requestAnimationFrame(detectFrame);
          }
        };

        detectFrame();
      } catch (err) {
        console.error("BarcodeDetector init failed", err);
      }
    };

    if (showScanner) {
      navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } })
        .then(s => {
          stream = s;
          if (videoRef.current) {
            videoRef.current.srcObject = s;
            startDetection();
          }
        })
        .catch(err => {
          console.error("Camera access denied", err);
          alert("Akses kamera ditolak. Harap izinkan kamera untuk menggunakan scanner.");
          setShowScanner(false);
        });
    }

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
      if (scanTimerRef.current) {
        cancelAnimationFrame(scanTimerRef.current);
      }
    };
  }, [showScanner]);

  return (
    <div className="h-full flex flex-col lg:flex-row gap-6 animate-in fade-in duration-300">
      {/* Product Selection */}
      <div className="flex-1 flex flex-col min-w-0">
        <div className="bg-white p-4 rounded-2xl border border-slate-200 mb-4 flex gap-4 shadow-sm">
          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Cari barcode atau nama produk..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 bg-slate-50 rounded-xl border-none outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
            />
          </div>
          <button 
            onClick={() => setShowScanner(true)}
            className="flex items-center gap-2 px-4 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-all shadow-md shadow-indigo-200"
          >
            <ScanLine size={18} />
            <span className="hidden sm:inline font-semibold">Scanner Kamera</span>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4 pb-4 pr-2 custom-scrollbar">
          {filteredProducts.map(product => (
            <button
              key={product.id}
              onClick={() => addToCart(product)}
              className="bg-white p-4 rounded-2xl border border-slate-200 hover:border-indigo-500 hover:shadow-xl transition-all text-left flex flex-col group relative overflow-hidden"
            >
              <div className="w-full aspect-square bg-slate-50 rounded-xl mb-3 flex items-center justify-center group-hover:bg-indigo-50 transition-colors">
                <Package className="text-slate-300 group-hover:text-indigo-400 transition-transform group-hover:scale-110" size={48} />
              </div>
              <h4 className="font-bold text-slate-800 text-sm truncate">{product.name}</h4>
              <p className="text-[10px] text-slate-400 font-mono tracking-tighter mb-2">{product.barcode}</p>
              <div className="mt-auto flex justify-between items-center">
                <span className="font-bold text-indigo-600">Rp {product.price.toLocaleString()}</span>
                <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold ${product.stock > 10 ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                  {product.stock} pcs
                </span>
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Cart & Checkout */}
      <div className="w-full lg:w-96 bg-white rounded-2xl border border-slate-200 shadow-2xl flex flex-col h-full overflow-hidden">
        <div className="p-5 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
          <div className="flex items-center gap-2 text-slate-800">
            <ShoppingCart size={20} className="text-indigo-600" />
            <h3 className="font-bold text-lg">Keranjang Belanja</h3>
          </div>
          <span className="bg-indigo-600 text-white px-3 py-1 rounded-full text-xs font-bold">{cart.length} Item</span>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
          {cart.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 gap-4 opacity-50">
              <div className="p-6 bg-slate-50 rounded-full">
                <ShoppingCart size={48} />
              </div>
              <p className="text-sm font-medium text-center">Belum ada item.<br/>Pilih produk atau gunakan scanner.</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.id} className="flex gap-3 bg-slate-50 p-3 rounded-xl border border-slate-100">
                <div className="w-12 h-12 bg-white rounded-lg flex items-center justify-center shrink-0 border border-slate-100">
                  <Package size={20} className="text-slate-400" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-bold text-slate-800 truncate">{item.name}</p>
                  <p className="text-xs text-indigo-600 font-bold">Rp {item.price.toLocaleString()}</p>
                </div>
                <div className="flex items-center gap-2">
                  <button onClick={() => updateQuantity(item.id, -1)} className="w-7 h-7 flex items-center justify-center bg-white border border-slate-200 rounded-lg text-slate-400 hover:text-red-600 transition-all">
                    <Minus size={14} />
                  </button>
                  <span className="w-6 text-center text-sm font-bold">{item.quantity}</span>
                  <button onClick={() => updateQuantity(item.id, 1)} className="w-7 h-7 flex items-center justify-center bg-white border border-slate-200 rounded-lg text-slate-400 hover:text-indigo-600 transition-all">
                    <Plus size={14} />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-6 bg-white border-t border-slate-100 space-y-5">
          <div className="space-y-2">
            <div className="flex justify-between text-xs text-slate-500 font-medium">
              <span>Subtotal</span>
              <span>Rp {subtotal.toLocaleString()}</span>
            </div>
            <div className="flex justify-between text-xs text-slate-500 font-medium">
              <span>PPN (11%)</span>
              <span>Rp {tax.toLocaleString()}</span>
            </div>
            <div className="flex justify-between text-xl font-black text-slate-900 pt-3 border-t border-dashed border-slate-200">
              <span>TOTAL</span>
              <span className="text-indigo-600">Rp {total.toLocaleString()}</span>
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex gap-2">
              {[
                { id: 'CASH', icon: Banknote, label: 'Tunai' },
                { id: 'CARD', icon: CreditCard, label: 'Kartu' },
                { id: 'QRIS', icon: QrCode, label: 'QRIS' },
              ].map(method => (
                <button
                  key={method.id}
                  onClick={() => setPaymentMethod(method.id as any)}
                  className={`flex-1 flex flex-col items-center gap-1.5 py-3 rounded-xl border-2 transition-all ${
                    paymentMethod === method.id 
                    ? 'border-indigo-600 bg-indigo-50 text-indigo-600' 
                    : 'border-slate-50 bg-slate-50 text-slate-400 hover:border-slate-200'
                  }`}
                >
                  <method.icon size={18} />
                  <span className="text-[10px] font-black uppercase tracking-wider">{method.label}</span>
                </button>
              ))}
            </div>

            {paymentMethod === 'CASH' && (
              <div className="space-y-3 p-4 bg-slate-50 rounded-2xl border border-slate-100 animate-in slide-in-from-bottom-2 duration-200">
                <div className="flex flex-col gap-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Uang Tunai Diterima</label>
                  <div className="relative">
                    <span className="absolute left-3 top-1/2 -translate-y-1/2 font-bold text-slate-400 text-sm">Rp</span>
                    <input 
                      type="number" 
                      value={cashReceived || ''}
                      onChange={(e) => setCashReceived(Number(e.target.value))}
                      placeholder="Masukkan nominal..."
                      className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl font-bold text-slate-800 outline-none focus:ring-2 focus:ring-indigo-500"
                    />
                  </div>
                </div>

                <div className="flex justify-between items-center px-1">
                  <span className="text-[10px] font-bold text-slate-400 uppercase">Kembalian</span>
                  <span className={`text-lg font-black ${changeDue > 0 ? 'text-emerald-600' : 'text-slate-300'}`}>
                    Rp {changeDue.toLocaleString()}
                  </span>
                </div>
              </div>
            )}
          </div>

          <button 
            disabled={cart.length === 0 || (paymentMethod === 'CASH' && cashReceived < total)}
            onClick={handleCheckout}
            className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-200 disabled:text-slate-400 text-white rounded-2xl font-bold shadow-xl shadow-indigo-100 transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
          >
            PROSES PEMBAYARAN
            <CheckCircle2 size={20} />
          </button>
        </div>
      </div>

      {/* Barcode Scanner Modal with Real Detection */}
      {showScanner && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className={`bg-white rounded-[2.5rem] w-full max-w-lg overflow-hidden flex flex-col shadow-2xl transition-all duration-300 ${scanFeedback ? 'ring-8 ring-emerald-400' : ''}`}>
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg">
                  <ScanLine size={20} />
                </div>
                <h3 className="font-bold text-xl text-slate-800">Pemindai Barcode</h3>
              </div>
              <button onClick={() => setShowScanner(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
                <X size={20} className="text-slate-500" />
              </button>
            </div>

            <div className="p-8 flex flex-col items-center">
              {!isDetectorSupported && (
                <div className="w-full bg-amber-50 border border-amber-200 p-4 rounded-xl mb-6 flex gap-3 text-amber-700">
                  <AlertCircle size={20} className="shrink-0" />
                  <p className="text-xs font-medium">Browser Anda tidak mendukung deteksi barcode otomatis. Gunakan input manual di bawah atau tombol simulasi.</p>
                </div>
              )}

              <div className="w-full aspect-video bg-slate-900 rounded-3xl overflow-hidden relative mb-8 shadow-inner border-4 border-slate-800">
                <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover opacity-80" />
                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                  <div className={`w-72 h-44 border-2 ${scanFeedback ? 'border-emerald-400 bg-emerald-400/10' : 'border-indigo-400/40'} rounded-3xl relative flex items-center justify-center transition-all duration-300 overflow-hidden`}>
                    <div className="absolute top-0 left-0 w-6 h-6 border-t-4 border-l-4 border-indigo-500 rounded-tl-xl"></div>
                    <div className="absolute top-0 right-0 w-6 h-6 border-t-4 border-r-4 border-indigo-500 rounded-tr-xl"></div>
                    <div className="absolute bottom-0 left-0 w-6 h-6 border-b-4 border-l-4 border-indigo-500 rounded-bl-xl"></div>
                    <div className="absolute bottom-0 right-0 w-6 h-6 border-b-4 border-r-4 border-indigo-500 rounded-br-xl"></div>
                    <div className={`w-full h-1 ${scanFeedback ? 'bg-emerald-400' : 'bg-indigo-500/50'} shadow-[0_0_20px_rgba(79,70,229,0.8)] animate-scan-fast`}></div>
                  </div>
                </div>
                {scanFeedback && (
                  <div className="absolute inset-0 bg-emerald-500/20 animate-pulse flex items-center justify-center">
                    <CheckCircle2 size={64} className="text-white" />
                  </div>
                )}
              </div>

              <div className="w-full space-y-4">
                <div className="relative group">
                  <ScanLine className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-500 transition-colors" size={20} />
                  <input 
                    ref={barcodeInputRef}
                    autoFocus
                    type="text" 
                    placeholder="Input Barcode Manual..."
                    value={manualBarcode}
                    onChange={(e) => {
                      const val = e.target.value;
                      setManualBarcode(val);
                      if (handleBarcodeDetect(val)) {
                        setManualBarcode('');
                      }
                    }}
                    className="w-full pl-12 pr-4 py-4 bg-slate-100 border-2 border-transparent rounded-2xl font-mono text-center text-lg focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-100 outline-none transition-all"
                  />
                </div>

                <div className="flex justify-center gap-2">
                  <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-3 py-1 bg-slate-100 rounded-full">
                    Deteksi: Real-Time
                  </span>
                  <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-3 py-1 bg-slate-100 rounded-full">
                    Kecepatan: 30 FPS
                  </span>
                </div>
              </div>

              <button 
                onClick={() => {
                   const randomProduct = products[Math.floor(Math.random() * products.length)];
                   handleBarcodeDetect(randomProduct.barcode);
                }}
                className="mt-8 w-full py-4 bg-slate-900 text-white rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-slate-800 transition-all active:scale-95"
              >
                <Camera size={20} />
                SIMULASI SCAN CEPAT
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Success Receipt Modal */}
      {showReceipt && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2rem] w-full max-w-sm overflow-hidden shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="p-8 flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mb-6 animate-bounce-short">
                <CheckCircle2 size={40} />
              </div>
              <h3 className="text-2xl font-black text-slate-800 mb-2">Belanja Selesai</h3>
              <p className="text-sm text-slate-500 mb-8">Transaksi #{showReceipt.id.split('-')[1]} sukses.</p>

              <div className="w-full bg-slate-50 rounded-2xl p-6 space-y-3 mb-8 text-left">
                <div className="flex justify-between text-xs font-bold text-slate-400 uppercase">
                  <span>Pembayaran</span>
                  <span className="text-slate-700">{showReceipt.paymentMethod}</span>
                </div>
                <div className="flex justify-between text-sm font-bold text-slate-700 pt-2 border-t border-slate-200">
                  <span>Total Tagihan</span>
                  <span>Rp {showReceipt.total.toLocaleString()}</span>
                </div>
                {showReceipt.paymentMethod === 'CASH' && (
                  <>
                    <div className="flex justify-between text-xs text-slate-500">
                      <span>Diterima</span>
                      <span>Rp {showReceipt.amountPaid.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between text-sm font-black text-emerald-600">
                      <span>Kembalian</span>
                      <span>Rp {showReceipt.changeDue.toLocaleString()}</span>
                    </div>
                  </>
                )}
              </div>

              <div className="w-full grid grid-cols-2 gap-4">
                <button 
                  onClick={() => setShowReceipt(null)}
                  className="py-4 bg-slate-100 text-slate-600 rounded-2xl font-bold hover:bg-slate-200 transition-all"
                >
                  Tutup
                </button>
                <button className="py-4 bg-indigo-600 text-white rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-indigo-700 transition-all">
                  <Printer size={18} />
                  Print Struk
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        @keyframes scan-fast {
          0%, 100% { transform: translateY(-80px); opacity: 0.2; }
          50% { transform: translateY(80px); opacity: 1; }
        }
        .animate-scan-fast {
          animation: scan-fast 1.5s ease-in-out infinite;
        }
        @keyframes bounce-short {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }
        .animate-bounce-short {
          animation: bounce-short 2s ease-in-out infinite;
        }
        .custom-scrollbar::-webkit-scrollbar {
          width: 5px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #e2e8f0;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #cbd5e1;
        }
      `}</style>
    </div>
  );
};

export default POSView;
